              try { fs.unlinkSync(dbPath); } catch (e) { /* ignore */ }
              done(err2);
            }
          });
          db2.on("error", (err2) => {
            try { fs.unlinkSync(dbPath); } catch (e) { /* ignore */ }
            done(err2);
          });
        } catch (err2) {
          try { fs.unlinkSync(dbPath); } catch (e) { /* ignore */ }
          done(err2);
        }
      }, 500);
    });

    db.on("error", (err) => {
      try { fs.unlinkSync(dbPath); } catch (e) { /* ignore */ }
